<?php if (!defined('ABSPATH')) exit; $cat = isset($_GET['categoria']) ? sanitize_text_field($_GET['categoria']) : ''; ?>
<div class="bg-white rounded-xl shadow-md p-6 sticky top-6"><h3 class="text-xl font-bold mb-4">Filtros</h3><form method="get"><div class="mb-6"><label class="block text-sm font-semibold mb-3">Categoría</label><?php $cats = get_terms(array('taxonomy' => 'categoria_marketplace', 'hide_empty' => true)); if ($cats) : echo '<div class="space-y-2">'; foreach ($cats as $c) : echo '<label class="flex items-center gap-2 p-2 hover:bg-gray-50 rounded"><input type="radio" name="categoria" value="' . $c->slug . '" ' . checked($cat, $c->slug, false) . ' onchange="this.form.submit()"/><span>' . $c->name . '</span></label>'; endforeach; echo '</div>'; endif; ?></div><?php if ($cat) : ?><a href="<?php echo get_post_type_archive_link('marketplace'); ?>" class="block text-center px-4 py-2 bg-gray-100 rounded-lg">Limpiar</a><?php endif; ?></form></div>
